#define PI_S 3.14159265359
float tempo_val = 2.0;

// Funzioni Hash uniche per evitare conflitti di nomi
float hash_s(float x) { return fract(sin(x) * 897612.531); }
float hsh_s(float x) { return fract(sin(x * 237.234234) * 982734.1235); }
float rnd_s(float x, float mn, float mx) { return mn + floor((mx - mn) * hash_s(floor(x))); }

float nse_s(float x) {
    float y = floor(x);
    float f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    return mix(hash_s(y), hash_s(y + 1.0), f) - 0.5;
}

// Strumento: Campana FM
vec2 inst_bell(float t, float f) {
    float m = sin(t * f * 80.0) * exp(t * -50.0);
    float sig = sin(t * f * PI_S * 2.0 + m) * min(t * 800.0, 1.0) * exp(t * -5.0) * 0.25;
    return vec2(sig);
}

// Strumento: Vocale "A"
float voc_s(float t, float f, float formant) {
    float x = fract(t * f) / f;
    return (sin(x * 6.0 * formant) * 0.4 + sin(x * 12.0 * formant) + sin(x * 26.0 * formant) * 0.2) * min(x * 1000.0, 1.0) * exp(x * -200.0);
}

// Coro Swarm (Ridotto a 4 voci per performance)
vec2 inst_choir(float t, float f) {
    vec2 v = vec2(0.0);
    float formant = 300.0 * exp2(sin(t * 0.1));
    for(int i = 0; i < 4; ++i) {
        float h = float(i);
        float m = voc_s(t + h / 3.0, f + pow(2.01, (h - 8.0) * 0.2), formant);
        float pan = hash_s(h);
        v.x += m * pan;
        v.y += m * (1.0 - pan);
    }
    return v * 0.15;
}

